// writeGateDoc writes an execution document with the flat execution: format.
func writeGateDoc(t *testing.T, dir, id, artifactID string, required bool, command []string) {
	t.Helper()
	path := filepath.Join(dir, "docs", "exec", id+".md")
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		t.Fatal(err)
	}
	cmdLines := ""
	for _, c := range command {
		cmdLines += "      - " + c + "\n"
	}
	reqStr := "false"
	if required {
		reqStr = "true"
	}
	content := "---\nddx:\n  id: " + id + "\n  depends_on:\n    - " + artifactID +
		"\n  execution:\n    kind: command\n    required: " + reqStr + "\n    command:\n" + cmdLines + "---\n# " + id + "\n"
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
}

// writeArtifactDoc writes a minimal governing artifact document.
func writeArtifactDoc(t *testing.T, dir, id string) {
	t.Helper()
	path := filepath.Join(dir, "docs", "specs", id+".md")
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		t.Fatal(err)
	}
	content := "---\nddx:\n  id: " + id + "\n---\n# " + id + "\n"
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
}

func TestEvaluateRequiredGates_NoGates(t *testing.T) {
	dir := t.TempDir()
	writeArtifactDoc(t, dir, "FEAT-TEST")

	results, anyFailed, _, err := evaluateRequiredGates(dir, []string{"FEAT-TEST"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if anyFailed {
		t.Error("expected no failure when no gates defined")
	}
	if len(results) != 0 {
		t.Errorf("expected empty results, got %d", len(results))
	}
}

func TestEvaluateRequiredGates_PassingGate(t *testing.T) {
	dir := t.TempDir()
	writeArtifactDoc(t, dir, "FEAT-PASS")
	writeGateDoc(t, dir, "exec.FEAT-PASS.smoke", "FEAT-PASS", true, []string{"sh", "-c", "exit 0"})

	results, anyFailed, _, err := evaluateRequiredGates(dir, []string{"FEAT-PASS"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if anyFailed {
		t.Error("expected no failure for passing gate")
	}
	if len(results) != 1 {
		t.Fatalf("expected 1 result, got %d", len(results))
	}
	if results[0].Status != "pass" {
		t.Errorf("expected pass, got %q", results[0].Status)
	}
}

func TestEvaluateRequiredGates_FailingGate(t *testing.T) {
	dir := t.TempDir()
	writeArtifactDoc(t, dir, "FEAT-FAIL")
	writeGateDoc(t, dir, "exec.FEAT-FAIL.smoke", "FEAT-FAIL", true, []string{"sh", "-c", "exit 1"})

	results, anyFailed, _, err := evaluateRequiredGates(dir, []string{"FEAT-FAIL"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !anyFailed {
		t.Error("expected anyFailed=true for failing required gate")
	}
	if len(results) != 1 {
		t.Fatalf("expected 1 result, got %d", len(results))
	}
	if results[0].Status != "fail" {
		t.Errorf("expected fail, got %q", results[0].Status)
	}
}

func TestEvaluateRequiredGates_OptionalGateNotRun(t *testing.T) {
	dir := t.TempDir()
	writeArtifactDoc(t, dir, "FEAT-OPT")
	// required=false gate — should not be included in results
	writeGateDoc(t, dir, "exec.FEAT-OPT.optional", "FEAT-OPT", false, []string{"sh", "-c", "exit 1"})

	results, anyFailed, _, err := evaluateRequiredGates(dir, []string{"FEAT-OPT"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if anyFailed {
		t.Error("optional gate should not cause failure")
	}
	if len(results) != 0 {
		t.Errorf("optional gate should not produce results, got %d", len(results))
	}
}

func TestEvaluateRequiredGates_UnrelatedGateIgnored(t *testing.T) {
	dir := t.TempDir()
	writeArtifactDoc(t, dir, "FEAT-A")
	writeArtifactDoc(t, dir, "FEAT-B")
	// Gate linked to FEAT-B only — should not run for FEAT-A
	writeGateDoc(t, dir, "exec.FEAT-B.smoke", "FEAT-B", true, []string{"sh", "-c", "exit 1"})

	results, anyFailed, _, err := evaluateRequiredGates(dir, []string{"FEAT-A"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if anyFailed {
		t.Error("gate for different artifact should not affect FEAT-A")
	}
	if len(results) != 0 {
		t.Errorf("unrelated gate should not produce results, got %d", len(results))
	}
}

func TestEvaluateRequiredGates_EmptyGoverningIDs(t *testing.T) {
	dir := t.TempDir()
	results, anyFailed, _, err := evaluateRequiredGates(dir, nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if anyFailed || len(results) != 0 {
		t.Error("empty governing IDs should produce no results")
	}
}

func TestSummarizeGates(t *testing.T) {
	tests := []struct {
		name     string
		results  []GateCheckResult
		failed   bool
		expected string
	}{
		{"no gates", nil, false, "skipped"},
		{"pass", []GateCheckResult{{Status: "pass"}}, false, "pass"},
		{"fail", []GateCheckResult{{Status: "fail"}}, true, "fail"},
		{"mixed fail", []GateCheckResult{{Status: "pass"}, {Status: "fail"}}, true, "fail"},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := summarizeGates(tc.results, tc.failed)
			if got != tc.expected {
				t.Errorf("got %q, want %q", got, tc.expected)
			}
		})
	}
}

package agent

// execute_bead_land_test.go — Land() coordinator-pattern unit tests.
//
// These tests run against a real temp git repo so they exercise the actual
// git plumbing (update-ref, merge --no-ff, worktree add, etc.) rather than a
// mock. Each scenario asserts that the target tip advances correctly and —
// crucially for replay fidelity — that the worker's own commit is never
// rewritten. Its parent always stays BaseRev so replay sees the same inputs
// the worker saw at execution time.

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"
	"testing"
	"time"
)

// ----------------------------------------------------------------------------
// Test helpers (real git repo fixtures)
// ----------------------------------------------------------------------------

type landTestRepo struct {
	t       *testing.T
	dir     string
	origin  string // path to a bare origin repo, or "" if no remote
	branch  string // target branch
	baseSHA string // the initial commit on the target branch
}

func newLandTestRepo(t *testing.T) *landTestRepo {
	t.Helper()
	dir := t.TempDir()
	r := &landTestRepo{t: t, dir: dir, branch: "main"}
	r.runGit("init", "-b", "main")
	r.runGit("config", "user.name", "Test")
	r.runGit("config", "user.email", "test@test.local")
	r.writeFile("README.md", "# test\n")
	r.runGit("add", "-A")
	r.runGit("commit", "-m", "init")
	r.baseSHA = r.resolveRef("refs/heads/main")
	return r
}

// newLandTestRepoWithOrigin creates a test repo whose origin is a separate
// bare repo. Used by the push-ff-only test.
func newLandTestRepoWithOrigin(t *testing.T) *landTestRepo {
	t.Helper()
	r := newLandTestRepo(t)

	bareDir := t.TempDir()
	cmd := exec.Command("git", "init", "--bare", "-b", "main", bareDir)
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("git init --bare: %s: %v", string(out), err)
	}
	r.origin = bareDir
	r.runGit("remote", "add", "origin", bareDir)
	r.runGit("push", "-u", "origin", "main")
	return r
}

func (r *landTestRepo) runGit(args ...string) string {
	r.t.Helper()
	cmd := exec.Command("git", append([]string{"-C", r.dir}, args...)...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		r.t.Fatalf("git %s: %s: %v", strings.Join(args, " "), string(out), err)
	}
	return strings.TrimSpace(string(out))
}

func (r *landTestRepo) writeFile(path, content string) {
	r.t.Helper()
	full := filepath.Join(r.dir, path)
	if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
		r.t.Fatal(err)
	}
	if err := os.WriteFile(full, []byte(content), 0o644); err != nil {
		r.t.Fatal(err)
	}
}

func (r *landTestRepo) resolveRef(ref string) string {
	r.t.Helper()
	return r.runGit("rev-parse", ref)
}

// commitOn creates a detached-head commit at baseSHA in a throwaway worktree
// and returns the new commit SHA. The commit is reachable via object store
// but not via any branch in the main repo, simulating what a worker worktree
// produces after ExecuteBead cleans up.
func (r *landTestRepo) commitOn(baseSHA, path, content, msg string) string {
	r.t.Helper()
	wt, err := os.MkdirTemp("", "land-test-wt-*")
	if err != nil {
		r.t.Fatal(err)
	}
	_ = os.RemoveAll(wt)
	r.runGit("worktree", "add", "--detach", wt, baseSHA)
	defer func() {
		r.runGit("worktree", "remove", "--force", wt)
		_ = os.RemoveAll(wt)
	}()

	if err := os.WriteFile(filepath.Join(wt, path), []byte(content), 0o644); err != nil {
		r.t.Fatal(err)
	}
	cmd := exec.Command("git", "-C", wt, "add", "-A")
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git add: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "-c", "user.name=Test", "-c", "user.email=test@test.local", "commit", "-m", msg)
	if out, err := cmd.CombinedOutput(); err != nil {
		r.t.Fatalf("git commit: %s: %v", string(out), err)
	}
	cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
	out, err := cmd.Output()
	if err != nil {
		r.t.Fatalf("git rev-parse HEAD: %v", err)
	}
	sha := strings.TrimSpace(string(out))

	// Pin the commit with a temporary ref so it survives the worktree
	// cleanup. The test caller is responsible for Land()-ing it later.
	ref := fmt.Sprintf("refs/ddx/test-pins/%s", sha[:12])
	r.runGit("update-ref", ref, sha)
	return sha
}

// mergeCommitCount returns the number of merge commits (commits with >1
// parent) reachable from ref. Used to assert merge-commit semantics on the
// merge path.
func (r *landTestRepo) mergeCommitCount(ref string) int {
	r.t.Helper()
	out := r.runGit("log", "--merges", "--format=%H", ref)
	if out == "" {
		return 0
	}
	return len(strings.Split(out, "\n"))
}

// commitCount returns the total number of commits reachable from ref.
func (r *landTestRepo) commitCount(ref string) int {
	r.t.Helper()
	out := r.runGit("rev-list", "--count", ref)
	n := 0
	_, _ = fmt.Sscanf(out, "%d", &n)
	return n
}

// commitParents returns the parent SHAs of sha.
func (r *landTestRepo) commitParents(sha string) []string {
	r.t.Helper()
	out := r.runGit("rev-list", "--parents", "-n", "1", sha)
	fields := strings.Fields(out)
	if len(fields) <= 1 {
		return nil
	}
	return fields[1:]
}

// shaReachable returns true when sha is reachable from ref via any commit
// path (including through merge commit parents).
func (r *landTestRepo) shaReachable(ref, sha string) bool {
	r.t.Helper()
	cmd := exec.Command("git", "-C", r.dir, "merge-base", "--is-ancestor", sha, ref)
	return cmd.Run() == nil
}

